from dataclasses import dataclass

@dataclass
class Money:
    cents: int
    def __post_init__(self):
        if self.cents < 0:
            raise ValueError('cents >= 0')
print(Money(10))
try:
    Money(-1)
except ValueError as e:
    print(e)

