class Person:
    def __init__(self, name):
        self.name = name
class Client(Person):
    def __init__(self, name, cid):
        super().__init__(name)
        self.cid = cid
print(Client('Ana','C1').name, Client('Ana','C1').cid)

class PersonInfo:
    def __init__(self, name): self.name = name
class Client:
    def __init__(self, cid, person: PersonInfo):
        self.cid = cid
        self.person = person
c=Client('C1', PersonInfo('Ana'))
print(c.cid, c.person.name)

from typing import Protocol

class EntityStore(Protocol):
    def get(self, id: str): ...
    def save(self, entity) -> None: ...

class InMemoryStore:
    def __init__(self):
        self._d = {}
    def get(self, id: str):
        return self._d.get(id)
    def save(self, entity) -> None:
        self._d[entity['id']] = entity
s=InMemoryStore(); s.save({'id':'C1'}); print(s.get('C1'))

class FakeStore:
    def get(self, id): return {'id': id, 'fake': True}
print(FakeStore().get('C9'))

