        return {
            'case_id': self.case_id,
            'entity_resolution_score': self.er_score,
            'relationship_signal_score': self.rel_score,
        }
print(Case('CASE-1', 0.9, 0.4).to_dict())

from dataclasses import dataclass

@dataclass
class Case:
    er: float
    rel: float
    def evidence_score(self):
        return round(0.6*self.er + 0.4*self.rel, 3)
print(Case(0.9, 0.4).evidence_score())

def validate_case(d):
    if not d.get('case_id'):
        raise ValueError('case_id required')
    for k in ('entity_resolution_score','relationship_signal_score'):
        v=d[k]
        if not isinstance(v, (int,float)) or not 0<=v<=1:
            raise ValueError(k)
    return True
print(validate_case({'case_id':'C','entity_resolution_score':0.5,'relationship_signal_score':0.2}))

